}

const Portfolio: React.FC<PortfolioProps> = ({ lang, projects }) => {
  const [activeCategory, setActiveCategory] = useState<ProjectCategory>(ProjectCategory.ALL);

  const filteredProjects = activeCategory === ProjectCategory.ALL 
    ? projects 
    : projects.filter(p => p.category === activeCategory);

  return (
    <div className="max-w-7xl mx-auto px-6 py-20">
      <header className="mb-20 text-center">
        <span className="text-panda-gold font-display text-sm tracking-widest uppercase mb-4 block">Galerie de Réalisations</span>
        <h1 className="text-6xl md:text-8xl font-display font-bold tracking-tighter mb-12">PORTFOLIO</h1>

        {/* Category Filters */}
        <div className="flex flex-wrap justify-center gap-4 border-b border-panda-white/10 pb-8">
          {CATEGORIES.map((cat) => (
            <button
              key={cat}
              onClick={() => setActiveCategory(cat as ProjectCategory)}
              className={`px-6 py-2 rounded-full text-sm font-medium transition-all uppercase tracking-widest border ${
                activeCategory === cat 
                ? 'bg-panda-gold border-panda-gold text-panda-black' 
                : 'border-panda-white/10 hover:border-panda-gold'
              }`}
            >
              {cat}
            </button>
          ))}
        </div>
      </header>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
        {filteredProjects.map((project) => (
          <div key={project.id} className="group relative bg-panda-white/5 border border-panda-white/10 overflow-hidden">
            <div className="aspect-square overflow-hidden">
              <img 
                src={project.image} 
                alt={project.title[lang]} 
                className="w-full h-full object-cover transition-transform duration-700 group-hover:scale-110"
              />
            </div>
            <div className="p-8">
              <span className="text-panda-gold text-xs font-bold uppercase tracking-widest mb-2 block">{project.category}</span>
              <h3 className="text-2xl font-display mb-4 group-hover:text-panda-gold transition-colors">{project.title[lang]}</h3>
