import React, { useState } from 'react';
import { Plus, Trash2, Edit2, Calendar, Layout, BookOpen, Send, Sparkles, Loader2 } from 'lucide-react';
import { Project, BlogPost, Appointment, ProjectCategory, Language } from '../types';
import { CATEGORIES } from '../constants';
import { translateContent, generateBlogPost } from '../geminiService';

interface AdminProps {
  lang: Language;
  projects: Project[];
  posts: BlogPost[];
  appointments: Appointment[];
  onAddProject: (p: Project) => void;
  onDeleteProject: (id: string) => void;
  onAddPost: (p: BlogPost) => void;
  onDeletePost: (id: string) => void;
}

const Admin: React.FC<AdminProps> = ({ 
  lang, projects, posts, appointments, 
  onAddProject, onDeleteProject, onAddPost, onDeletePost 
}) => {
  const [tab, setTab] = useState<'projects' | 'blog' | 'appointments'>('projects');
  const [isGenerating, setIsGenerating] = useState(false);
  const [newTopic, setNewTopic] = useState('');

  const handleGeneratePost = async () => {
    if (!newTopic) return;
    setIsGenerating(true);
    const content = await generateBlogPost(newTopic, lang);
    if (content) {
      // Create multi-lang placeholders
      const post: BlogPost = {
        id: Math.random().toString(36).substring(7),
        title: { fr: content.title, en: content.title, de: content.title },
        content: { fr: content.content, en: content.content, de: content.content },
        date: new Date().toLocaleDateString(),
        image: `https://picsum.photos/seed/${Math.random()}/1200/600`
      };
      onAddPost(post);
      setNewTopic('');
    }
    setIsGenerating(false);
  };

  return (
    <div className="max-w-7xl mx-auto px-6 py-20">
      <header className="flex flex-col md:flex-row md:items-center justify-between gap-8 mb-16">
        <div>
          <h1 className="text-4xl font-display font-bold uppercase tracking-tighter">Gestion du <span className="text-panda-gold">Portfolio</span></h1>
          <p className="text-panda-white/50">Interface de gestion Panda_Graphic (CMS)</p>
        </div>
        <div className="flex bg-panda-white/5 p-1 rounded-2xl border border-panda-white/10">
          {[
            { id: 'projects', icon: <Layout size={18} />, label: 'Projets' },
            { id: 'blog', icon: <BookOpen size={18} />, label: 'Blog' },
            { id: 'appointments', icon: <Calendar size={18} />, label: 'RDV' }
          ].map(t => (
            <button
              key={t.id}
              onClick={() => setTab(t.id as any)}
              className={`flex items-center space-x-2 px-6 py-3 rounded-xl transition-all uppercase tracking-widest text-xs font-bold ${
                tab === t.id ? 'bg-panda-gold text-panda-black shadow-lg shadow-panda-gold/20' : 'hover:bg-panda-white/5'
              }`}
            >
              {t.icon} <span>{t.label}</span>
            </button>
          ))}
        </div>
      </header>

      {tab === 'projects' && (
        <div className="space-y-8">
          <div className="bg-panda-white/5 border border-panda-white/10 p-8 rounded-3xl">
            <h3 className="text-xl font-bold mb-6 flex items-center space-x-2"><Plus size={20} className="text-panda-gold" /> <span>Nouveau Projet</span></h3>
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
              <input placeholder="Titre (FR)" className="bg-panda-black/50 border border-panda-white/10 p-4 rounded-xl outline-none focus:border-panda-gold" />
              <select className="bg-panda-black/50 border border-panda-white/10 p-4 rounded-xl outline-none focus:border-panda-gold">
                {CATEGORIES.map(c => <option key={c} value={c}>{c}</option>)}
              </select>
              <input placeholder="URL Image" className="bg-panda-black/50 border border-panda-white/10 p-4 rounded-xl outline-none focus:border-panda-gold" />
              <button className="bg-panda-green text-panda-white font-bold uppercase tracking-widest text-xs py-4 rounded-xl hover:bg-panda-green/80 transition-all">Ajouter</button>
            </div>
          </div>

          <div className="grid grid-cols-1 gap-4">
            {projects.map(p => (
              <div key={p.id} className="flex items-center justify-between p-6 bg-panda-white/5 border border-panda-white/10 rounded-2xl hover:bg-panda-white/10 transition-all group">
                <div className="flex items-center space-x-6">
                  <img src={p.image} className="w-16 h-16 object-cover rounded-xl grayscale group-hover:grayscale-0 transition-all" />
                  <div>
                    <h4 className="font-bold text-lg">{p.title[lang]}</h4>
                    <span className="text-xs text-panda-gold uppercase tracking-[0.2em]">{p.category}</span>
                  </div>
                </div>
                <button onClick={() => onDeleteProject(p.id)} className="p-3 bg-red-500/10 text-red-500 rounded-xl hover:bg-red-500 hover:text-white transition-all">
                  <Trash2 size={20} />
                </button>
              </div>
            ))}
          </div>
        </div>
      )}

      {tab === 'blog' && (
        <div className="space-y-8">
          <div className="bg-panda-gold/10 border border-panda-gold/20 p-8 rounded-3xl">
            <h3 className="text-xl font-bold mb-6 flex items-center space-x-2 text-panda-gold">
              <Sparkles size={20} /> <span>Générateur d'Article IA</span>
