          </div>

          <div className="grid grid-cols-1 gap-4">
            {posts.map(p => (
              <div key={p.id} className="flex items-center justify-between p-6 bg-panda-white/5 border border-panda-white/10 rounded-2xl">
                <div>
                  <h4 className="font-bold text-lg">{p.title[lang]}</h4>
                  <span className="text-xs text-panda-white/40 uppercase tracking-widest">{p.date}</span>
                </div>
                <button onClick={() => onDeletePost(p.id)} className="p-3 bg-red-500/10 text-red-500 rounded-xl hover:bg-red-500 hover:text-white transition-all">
                  <Trash2 size={20} />
                </button>
              </div>
            ))}
          </div>
        </div>
      )}

      {tab === 'appointments' && (
        <div className="space-y-4">
          {appointments.length === 0 ? (
            <div className="text-center py-20 opacity-40 italic">Aucune prise de rendez-vous enregistrée.</div>
          ) : (
            appointments.map(a => (
              <div key={a.id} className="flex flex-col md:flex-row md:items-center justify-between p-8 bg-panda-white/5 border border-panda-white/10 rounded-3xl">
                <div className="flex items-center space-x-6 mb-4 md:mb-0">
                  <div className="w-12 h-12 bg-panda-gold/20 text-panda-gold rounded-full flex items-center justify-center font-bold">
                    {a.name.charAt(0)}
                  </div>
                  <div>
                    <h4 className="font-bold text-xl">{a.name}</h4>
                    <p className="text-panda-white/60 text-sm flex items-center space-x-2">
                      <Mail size={12} /> <span>{a.email}</span>
                    </p>
                  </div>
                </div>
                <div className="grid grid-cols-2 md:grid-cols-3 gap-8">
                  <div className="text-right">
                    <span className="text-[10px] uppercase tracking-[0.2em] text-panda-white/40 block">Service</span>
                    <span className="font-bold text-panda-gold">{a.service}</span>
