import { GoogleGenAI, Type } from "@google/genai";

// Always use the named parameter and direct process.env.API_KEY access
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const translateContent = async (text: string, targetLang: string) => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Translate the following text into ${targetLang}. Only return the translation: "${text}"`,
    });
    // Use the .text property directly
    return response.text?.trim() || text;
  } catch (error) {
    console.error("Translation error:", error);
    return text;
  }
};

export const generateBlogPost = async (topic: string, lang: string) => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Write a creative and professional blog post in ${lang} for a graphic design portfolio called Panda_Graphic about: ${topic}. Structure it with a title and body text.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            title: { type: Type.STRING },
            content: { type: Type.STRING }
          },
          required: ["title", "content"]
        }
      }
    });
    // Use the .text property directly
    return JSON.parse(response.text || '{}');
  } catch (error) {
    console.error("Generation error:", error);
    return null;
  }
};

