      delay: '500ms'
    },
    {
      title: 'Galerie Créative',
      icon: <ImageIcon className="text-panda-gold" size={40} />,
      description: 'Projets artistiques et expérimentations visuelles. Pour ceux qui cherchent l\'exclusivité et l\'originalité pure.',
      items: ['Illustrations Premium', 'Retouche d\'art', 'Collages digitaux', 'Prints de collection'],
      delay: '600ms'
    }
  ];

  return (
