      <header className="mb-24 reveal text-center md:text-left">
        <div className="inline-block bg-panda-gold/10 border border-panda-gold/20 text-panda-gold px-6 py-2 rounded-full mb-6 text-xs font-bold uppercase tracking-[0.4em]">
          Catalogue d'Expertise
        </div>
        <h1 className="text-6xl md:text-8xl font-display font-bold tracking-tighter mb-8 uppercase leading-none">
          Mes <span className="text-panda-gold">Services</span>
        </h1>
        <p className="text-2xl text-panda-white/60 max-w-3xl font-light leading-relaxed">
          Propulsez votre marque avec Victor Gabriel Archange. Un design audacieux, des détails dorés et une vision sans compromis.
        </p>
      </header>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
        {serviceList.map((service, i) => (
          <div 
            key={i} 
            className="reveal p-10 bg-panda-white/5 border border-panda-white/10 rounded-[2.5rem] group hover:bg-panda-white/10 hover:border-panda-gold transition-all duration-700 relative overflow-hidden h-full flex flex-col"
            style={{ transitionDelay: service.delay }}
          >
            <div className="absolute inset-0 marble-texture opacity-0 group-hover:opacity-5 transition-opacity duration-1000 pointer-events-none" />

            <div className="mb-8 transform group-hover:scale-110 group-hover:animate-float transition-all duration-500">
              <div className="w-16 h-16 bg-panda-gold/10 flex items-center justify-center rounded-2xl border border-panda-gold/20">
                {service.icon}
              </div>
            </div>

            <h3 className="text-xl font-display mb-4 uppercase tracking-tight group-hover:text-panda-gold transition-colors flex items-center justify-between">
              <span>{service.title}</span>
              <ArrowUpRight size={18} className="opacity-0 group-hover:opacity-100 transition-all" />
            </h3>

            <p className="text-panda-white/40 mb-8 font-light text-sm leading-relaxed">
              {service.description}
            </p>

            <ul className="space-y-3 mt-auto">
              {service.items.map((item, j) => (
                <li key={j} className="flex items-center space-x-3 text-xs text-panda-white/60 group-hover:text-panda-white/90">
                  <CheckCircle2 size={14} className="text-panda-green opacity-50" />
                  <span className="tracking-wide">{item}</span>
                </li>
              ))}
            </ul>
          </div>
        ))}
      </div>

      {/* FINAL CTA SECTION - Progressive & High Contrast */}
      <div className="mt-32 p-12 md:p-24 marble-texture rounded-[4rem] text-center border border-panda-black/5 overflow-hidden">
        <div className="reveal flex flex-col items-center">
          <Sparkles className="text-panda-gold mb-8 animate-float" size={48} />

          <h2 className="reveal transition-delay-150 text-4xl md:text-5xl font-display uppercase mb-6 text-panda-black leading-tight">
            Besoin d'un <span className="text-panda-green underline underline-offset-8">Chef-d'œuvre</span> ?
          </h2>

          <p className="reveal transition-delay-300 text-xl text-panda-black/90 max-w-2xl mx-auto mb-12 font-semibold leading-relaxed">
            Ne laissez plus votre image au hasard. Prenons rendez-vous pour donner vie à votre vision.
          </p>

          <button 
            onClick={() => navigate('/contact')}
            className="reveal transition-delay-500 px-12 py-5 bg-[#121212] text-white font-bold uppercase tracking-[0.2em] rounded-xl hover:bg-panda-gold hover:text-panda-black transition-all shadow-2xl transform hover:scale-105 active:scale-95 border border-white/10"
          >
            Lancer mon projet
          </button>
        </div>
      </div>
    </div>
  );
};

