import React, { useState, useRef } from 'react';
import { 
  Plus, Trash2, Calendar, Layout, BookOpen, 
  Sparkles, Loader2, Mail, Lock, Unlock, 
  ArrowRight, Upload, Image as ImageIcon, Film, X 
} from 'lucide-react';
import { Project, BlogPost, Appointment, ProjectCategory, Language } from '../types';
import { CATEGORIES } from '../constants';
import { translateContent, generateBlogPost } from '../geminiService';

interface AdminProps {
  lang: Language;
  projects: Project[];
  posts: BlogPost[];
  appointments: Appointment[];
  onAddProject: (p: Project) => void;
  onDeleteProject: (id: string) => void;
  onAddPost: (p: BlogPost) => void;
  onDeletePost: (id: string) => void;
}

const ADMIN_CODE = "PANDA2025";

const Admin: React.FC<AdminProps> = ({ 
  lang, projects, posts, appointments, 
  onAddProject, onDeleteProject, onAddPost, onDeletePost 
}) => {
  const [tab, setTab] = useState<'projects' | 'blog' | 'appointments'>('projects');
  const [isGenerating, setIsGenerating] = useState(false);
  const [newTopic, setNewTopic] = useState('');

  // Nouveaux états pour l'ajout de projet
  const [newProjectTitle, setNewProjectTitle] = useState('');
  const [newProjectCategory, setNewProjectCategory] = useState<ProjectCategory>(ProjectCategory.GALLERY);
  const [previewMedia, setPreviewMedia] = useState<string | null>(null);
  const [mediaType, setMediaType] = useState<'image' | 'video'>('image');
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Auth state
  const [isAuthorized, setIsAuthorized] = useState(false);
  const [code, setCode] = useState('');
  const [error, setError] = useState(false);

  const handleAuth = (e: React.FormEvent) => {
    e.preventDefault();
    if (code === ADMIN_CODE) {
      setIsAuthorized(true);
      setError(false);
    } else {
      setError(true);
      setCode('');
    }
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const isVideo = file.type.startsWith('video/');
      setMediaType(isVideo ? 'video' : 'image');

      const reader = new FileReader();
      reader.onloadend = () => {
        setPreviewMedia(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const resetProjectForm = () => {
    setNewProjectTitle('');
    setPreviewMedia(null);
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  const handleAddProject = () => {
    if (!newProjectTitle || !previewMedia) return;

    const project: Project = {
      id: Math.random().toString(36).substring(7),
      title: { fr: newProjectTitle, en: newProjectTitle, de: newProjectTitle },
      category: newProjectCategory,
      image: previewMedia,
      mediaType: mediaType,
      description: { 
        fr: 'Nouveau projet ajouté via CMS.', 
        en: 'New project added via CMS.', 
        de: 'Neues Projekt über CMS hinzugefügt.' 
      }
    };

    onAddProject(project);
    resetProjectForm();
  };

  const handleGeneratePost = async () => {
    if (!newTopic) return;
    setIsGenerating(true);
    const content = await generateBlogPost(newTopic, lang);
    if (content) {
      const post: BlogPost = {
        id: Math.random().toString(36).substring(7),
        title: { fr: content.title, en: content.title, de: content.title },
        content: { fr: content.content, en: content.content, de: content.content },
        date: new Date().toLocaleDateString(),
        image: `https://picsum.photos/seed/${Math.random()}/1200/600`
      };
      onAddPost(post);
      setNewTopic('');
    }
    setIsGenerating(false);
  };

  if (!isAuthorized) {
    return (
      <div className="min-h-[80vh] flex items-center justify-center px-6">
        <div className="max-w-md w-full bg-panda-white/5 border border-panda-white/10 p-12 rounded-[2.5rem] text-center backdrop-blur-xl">
          <div className="w-20 h-20 bg-panda-gold/10 text-panda-gold rounded-full flex items-center justify-center mx-auto mb-8 border border-panda-gold/20">
            <Lock size={32} />
          </div>
          <h1 className="text-3xl font-display font-bold mb-2 uppercase">Accès Réservé</h1>
          <p className="text-panda-white/50 text-sm mb-10">Veuillez entrer le code d'accès Panda_Graphic</p>

          <form onSubmit={handleAuth} className="space-y-6">
            <input 
              type="password"
              placeholder="••••••••"
              value={code}
              onChange={(e) => { setCode(e.target.value); setError(false); }}
              className={`w-full bg-panda-black border px-6 py-4 rounded-xl outline-none text-center text-2xl tracking-[0.5em] transition-all ${
                error ? 'border-red-500 animate-shake' : 'border-panda-white/10 focus:border-panda-gold'
              }`}
            />
            {error && <p className="text-red-500 text-xs font-bold uppercase tracking-widest">Code incorrect</p>}
            <button className="w-full py-5 bg-panda-gold text-panda-black font-bold uppercase tracking-[0.3em] rounded-xl hover:bg-panda-gold/90 transition-all flex items-center justify-center space-x-3">
              <span>Débloquer</span>
              <ArrowRight size={18} />
            </button>
          </form>
        </div>
      </div>
    );
  }

  return (
    <div className="max-w-7xl mx-auto px-6 py-20 animate-in fade-in duration-700">
      <header className="flex flex-col md:flex-row md:items-center justify-between gap-8 mb-16">
        <div className="flex items-center space-x-4">
          <div className="p-3 bg-panda-green/20 text-panda-green rounded-xl">
            <Unlock size={24} />
          </div>
          <div>
            <h1 className="text-4xl font-display font-bold uppercase tracking-tighter text-panda-white">Gestion du <span className="text-panda-gold">Portfolio</span></h1>
            <p className="text-panda-white/50">Bienvenue, Victor Gabriel Archange</p>
          </div>
        </div>
        <div className="flex bg-panda-white/5 p-1 rounded-2xl border border-panda-white/10">
          {[
            { id: 'projects', icon: <Layout size={18} />, label: 'Projets' },
            { id: 'blog', icon: <BookOpen size={18} />, label: 'Blog' },
            { id: 'appointments', icon: <Calendar size={18} />, label: 'RDV' }
          ].map(t => (
            <button
              key={t.id}
              onClick={() => setTab(t.id as any)}
              className={`flex items-center space-x-2 px-6 py-3 rounded-xl transition-all uppercase tracking-widest text-xs font-bold ${
                tab === t.id ? 'bg-panda-gold text-panda-black shadow-lg shadow-panda-gold/20' : 'hover:bg-panda-white/5 text-panda-white'
              }`}
            >
              {t.icon} <span>{t.label}</span>
            </button>
          ))}
        </div>
      </header>

      {tab === 'projects' && (
        <div className="space-y-8">
          {/* Nouveau formulaire d'ajout avec Upload */}
          <div className="bg-panda-white/5 border border-panda-white/10 p-10 rounded-[2.5rem] reveal">
            <h3 className="text-2xl font-display font-bold mb-8 flex items-center space-x-3 uppercase tracking-tighter">
              <Plus size={24} className="text-panda-gold" /> 
              <span>Nouveau Chef-d'œuvre</span>
            </h3>

            <div className="grid grid-cols-1 lg:grid-cols-2 gap-12">
              <div className="space-y-6">
                <div>
                  <label className="text-[10px] uppercase font-black tracking-widest text-panda-gold mb-2 block">Titre du Projet</label>
                  <input 
                    placeholder="Ex: Identité Bambout-Or" 
                    value={newProjectTitle}
                    onChange={(e) => setNewProjectTitle(e.target.value)}
                    className="w-full bg-panda-black/50 border border-panda-white/10 p-5 rounded-2xl outline-none focus:border-panda-gold text-panda-white transition-all" 
                  />
                </div>

                <div>
                  <label className="text-[10px] uppercase font-black tracking-widest text-panda-gold mb-2 block">Catégorie</label>
                  <select 
                    value={newProjectCategory}
                    onChange={(e) => setNewProjectCategory(e.target.value as ProjectCategory)}
                    className="w-full bg-panda-black/50 border border-panda-white/10 p-5 rounded-2xl outline-none focus:border-panda-gold text-panda-white transition-all"
                  >
                    {CATEGORIES.map(c => <option key={c} value={c}>{c}</option>)}
                  </select>
                </div>

                <button 
                  onClick={handleAddProject}
                  disabled={!newProjectTitle || !previewMedia}
                  className="w-full py-5 bg-panda-gold text-panda-black font-bold uppercase tracking-[0.2em] rounded-2xl hover:bg-panda-gold/80 transition-all flex items-center justify-center space-x-3 disabled:opacity-30 shadow-xl"
                >
                  <Sparkles size={20} />
                  <span>Publier sur le Portfolio</span>
                </button>
              </div>

              {/* Zone d'Upload Interactive */}
              <div 
                onClick={() => fileInputRef.current?.click()}
                className={`relative group border-2 border-dashed rounded-[2.5rem] flex flex-col items-center justify-center p-8 transition-all cursor-pointer min-h-[300px] ${
                  previewMedia ? 'border-panda-green/50 bg-panda-green/5' : 'border-panda-gold/30 hover:border-panda-gold bg-panda-white/5'
                }`}
              >
                <input 
                  type="file" 
                  ref={fileInputRef} 
                  className="hidden" 
                  accept="image/*,video/*"
                  onChange={handleFileChange} 
                />

                {previewMedia ? (
                  <div className="relative w-full h-full">
                    {mediaType === 'image' ? (
                      <img src={previewMedia} className="w-full h-48 object-cover rounded-2xl mb-4" />
                    ) : (
                      <video src={previewMedia} className="w-full h-48 object-cover rounded-2xl mb-4" />
                    )}
                    <div className="absolute top-2 right-2 flex space-x-2">
                       <button 
                         onClick={(e) => { e.stopPropagation(); resetProjectForm(); }}
                         className="p-2 bg-red-500 rounded-full text-white shadow-lg"
                       >
                         <X size={16} />
                       </button>
                    </div>
                    <div className="flex items-center justify-center space-x-2 text-panda-green font-bold text-xs uppercase tracking-widest">
                      <CheckCircle size={16} />
                      <span>Fichier prêt ({mediaType})</span>
                    </div>
                  </div>
                ) : (
                  <div className="text-center group-hover:scale-110 transition-transform duration-500">
                    <div className="w-20 h-20 bg-panda-gold/10 text-panda-gold rounded-full flex items-center justify-center mx-auto mb-6">
                      <Upload size={32} />
                    </div>
                    <h4 className="text-panda-white font-bold mb-2 uppercase tracking-tight">Charger Image ou Vidéo</h4>
                    <p className="text-panda-white/40 text-xs">Glissez-déposez ou cliquez pour explorer</p>
                    <div className="mt-6 flex justify-center space-x-4 opacity-50">
                      <ImageIcon size={20} className="text-panda-gold" />
                      <Film size={20} className="text-panda-gold" />
                    </div>
                  </div>
                )}
              </div>
            </div>
          </div>

          <div className="grid grid-cols-1 gap-6">
            <h4 className="text-sm font-bold uppercase tracking-widest text-panda-white/40 mb-2">Projets en ligne ({projects.length})</h4>
            {projects.map(p => (
              <div key={p.id} className="flex items-center justify-between p-6 bg-panda-white/5 border border-panda-white/10 rounded-3xl hover:bg-panda-white/10 transition-all group">
                <div className="flex items-center space-x-6">
                  <div className="w-16 h-16 relative rounded-xl overflow-hidden bg-panda-black border border-panda-white/10">
                    {p.mediaType === 'video' ? (
                      <video src={p.image} className="w-full h-full object-cover grayscale group-hover:grayscale-0" />
                    ) : (
                      <img src={p.image} className="w-full h-full object-cover grayscale group-hover:grayscale-0" />
                    )}
                    <div className="absolute top-1 left-1">
                       {p.mediaType === 'video' ? <Film size={12} className="text-panda-gold" /> : <ImageIcon size={12} className="text-panda-gold" />}
                    </div>
                  </div>
                  <div>
                    <h4 className="font-bold text-lg text-panda-white">{p.title[lang]}</h4>
                    <span className="text-xs text-panda-gold uppercase tracking-[0.2em] font-black">{p.category}</span>
                  </div>
                </div>
                <button onClick={() => onDeleteProject(p.id)} className="p-4 bg-red-500/10 text-red-500 rounded-2xl hover:bg-red-500 hover:text-white transition-all shadow-lg">
                  <Trash2 size={20} />
                </button>
              </div>
            ))}
          </div>
        </div>
      )}

      {/* Reste du composant (Blog / Appointments) inchangé */}
      {tab === 'blog' && (
        <div className="space-y-8">
          <div className="bg-panda-gold/10 border border-panda-gold/20 p-8 rounded-3xl">
            <h3 className="text-xl font-bold mb-6 flex items-center space-x-2 text-panda-gold">
              <Sparkles size={20} /> <span>Générateur d'Article IA</span>
            </h3>
            <div className="flex space-x-4">
              <input 
                placeholder="Ex: Les tendances packaging 2025" 
                className="flex-1 bg-panda-black/50 border border-panda-white/10 p-4 rounded-xl outline-none focus:border-panda-gold text-panda-white"
                value={newTopic}
                onChange={(e) => setNewTopic(e.target.value)}
              />
              <button 
                onClick={handleGeneratePost}
                disabled={isGenerating}
                className="bg-panda-gold text-panda-black px-8 py-4 rounded-xl font-bold uppercase text-xs tracking-widest flex items-center space-x-2 disabled:opacity-50"
              >
                {isGenerating ? <Loader2 className="animate-spin" size={18} /> : <Sparkles size={18} />}
                <span>Générer</span>
              </button>
            </div>
          </div>

          <div className="grid grid-cols-1 gap-4">
            {posts.map(p => (
              <div key={p.id} className="flex items-center justify-between p-6 bg-panda-white/5 border border-panda-white/10 rounded-2xl">
                <div>
                  <h4 className="font-bold text-lg text-panda-white">{p.title[lang]}</h4>
                  <span className="text-xs text-panda-white/40 uppercase tracking-widest">{p.date}</span>
                </div>
                <button onClick={() => onDeletePost(p.id)} className="p-3 bg-red-500/10 text-red-500 rounded-xl hover:bg-red-500 hover:text-white transition-all">
                  <Trash2 size={20} />
                </button>
              </div>
            ))}
          </div>
        </div>
      )}

      {tab === 'appointments' && (
        <div className="space-y-4">
          {appointments.length === 0 ? (
            <div className="text-center py-20 opacity-40 italic text-panda-white">Aucune prise de rendez-vous enregistrée.</div>
          ) : (
            appointments.map(a => (
