            <h4 className="text-sm font-bold uppercase tracking-widest text-panda-white/40 mb-2">Projets en ligne ({projects.length})</h4>
            {projects.map(p => (
              <div key={p.id} className="flex items-center justify-between p-6 bg-panda-white/5 border border-panda-white/10 rounded-3xl hover:bg-panda-white/10 transition-all group">
                <div className="flex items-center space-x-6">
