        </div>
      )}

      {tab === 'appointments' && (
        <div className="space-y-4">
          {appointments.length === 0 ? (
            <div className="text-center py-20 opacity-40 italic text-panda-white">Aucune prise de rendez-vous enregistrée.</div>
