import React, { useState, useRef } from 'react';
import { 
  Plus, Trash2, Calendar, Layout, BookOpen, 
  Sparkles, Loader2, Mail, Lock, Unlock, 
  ArrowRight, Upload, Image as ImageIcon, Film, X, FileText, CheckCircle, Clock, User
} from 'lucide-react';
import { Project, BlogPost, Appointment, ProjectCategory, Language } from '../types';
import { CATEGORIES } from '../constants';
import { translateContent, generateBlogPost } from '../geminiService';

interface AdminProps {
  lang: Language;
  projects: Project[];
  posts: BlogPost[];
  appointments: Appointment[];
  onAddProject: (p: Project) => void;
  onDeleteProject: (id: string) => void;
  onAddPost: (p: BlogPost) => void;
  onDeletePost: (id: string) => void;
  isAdmin: boolean;
  setIsAdmin: (val: boolean) => void;
}

const ADMIN_CODE = "PANDA2025";

const Admin: React.FC<AdminProps> = ({ 
  lang, projects, posts, appointments, 
  onAddProject, onDeleteProject, onAddPost, onDeletePost,
  isAdmin, setIsAdmin
}) => {
  const [tab, setTab] = useState<'projects' | 'blog' | 'appointments'>('projects');
  const [isGenerating, setIsGenerating] = useState(false);
  const [newTopic, setNewTopic] = useState('');

  // Project form states
  const [newProjectTitle, setNewProjectTitle] = useState('');
  const [newProjectDesc, setNewProjectDesc] = useState('');
  const [newProjectCaseStudy, setNewProjectCaseStudy] = useState('');
  const [newProjectCategory, setNewProjectCategory] = useState<ProjectCategory>(ProjectCategory.GALLERY);
  const [previewMedia, setPreviewMedia] = useState<string | null>(null);
  const [mediaType, setMediaType] = useState<'image' | 'video'>('image');
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Blog form states
  const [blogTitle, setBlogTitle] = useState('');
  const [blogContent, setBlogContent] = useState('');
  const [blogMedia, setBlogMedia] = useState<string | null>(null);
  const [blogMediaType, setBlogMediaType] = useState<'image' | 'video'>('image');
  const blogFileInputRef = useRef<HTMLInputElement>(null);

  // Auth state
  const [code, setCode] = useState('');
  const [error, setError] = useState(false);

  const handleAuth = (e: React.FormEvent) => {
    e.preventDefault();
    if (code === ADMIN_CODE) {
      setIsAdmin(true);
      setError(false);
    } else {
      setError(true);
      setCode('');
    }
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>, target: 'project' | 'blog') => {
    const file = e.target.files?.[0];
    if (file) {
      const isVideo = file.type.startsWith('video/');
      const reader = new FileReader();
      reader.onloadend = () => {
        if (target === 'project') {
          setMediaType(isVideo ? 'video' : 'image');
          setPreviewMedia(reader.result as string);
        } else {
          setBlogMediaType(isVideo ? 'video' : 'image');
          setBlogMedia(reader.result as string);
        }
      };
      reader.readAsDataURL(file);
    }
  };

  const resetProjectForm = () => {
    setNewProjectTitle('');
    setNewProjectDesc('');
    setNewProjectCaseStudy('');
    setPreviewMedia(null);
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  const resetBlogForm = () => {
    setBlogTitle('');
    setBlogContent('');
    setBlogMedia(null);
    if (blogFileInputRef.current) blogFileInputRef.current.value = '';
  };

  const handleAddProject = async () => {
    if (!newProjectTitle || !previewMedia) return;
    setIsGenerating(true);
    try {
      const titleEN = await translateContent(newProjectTitle, 'en');
      const titleDE = await translateContent(newProjectTitle, 'de');
      const descEN = await translateContent(newProjectDesc, 'en');
      const descDE = await translateContent(newProjectDesc, 'de');
      const studyEN = await translateContent(newProjectCaseStudy, 'en');
      const studyDE = await translateContent(newProjectCaseStudy, 'de');

      const project: Project = {
        id: Math.random().toString(36).substring(7),
        title: { fr: newProjectTitle, en: titleEN, de: titleDE },
        category: newProjectCategory,
        image: previewMedia,
        mediaType: mediaType,
        description: { fr: newProjectDesc, en: descEN, de: descDE },
        caseStudy: { fr: newProjectCaseStudy, en: studyEN, de: studyDE }
      };

      onAddProject(project);
      resetProjectForm();
    } finally {
      setIsGenerating(false);
    }
  };

  const handleAddBlogPost = async () => {
    if (!blogTitle || !blogMedia) return;
    setIsGenerating(true);
    try {
      const titleEN = await translateContent(blogTitle, 'en');
      const titleDE = await translateContent(blogTitle, 'de');
      const contentEN = await translateContent(blogContent, 'en');
      const contentDE = await translateContent(blogContent, 'de');

      const post: BlogPost = {
        id: Math.random().toString(36).substring(7),
        title: { fr: blogTitle, en: titleEN, de: titleDE },
        content: { fr: blogContent, en: contentEN, de: contentDE },
        date: new Date().toLocaleDateString(),
        image: blogMedia,
        mediaType: blogMediaType,
        likes: 0,
        comments: []
      };

      onAddPost(post);
      resetBlogForm();
    } finally {
      setIsGenerating(false);
    }
  };

  const handleGeneratePost = async () => {
    if (!newTopic) return;
    setIsGenerating(true);
    try {
      const content = await generateBlogPost(newTopic, lang);
      if (content) {
        setBlogTitle(content.title);
        setBlogContent(content.content);
        setBlogMedia(`https://picsum.photos/seed/${Math.random()}/1200/800`);
        setBlogMediaType('image');
      }
    } finally {
      setIsGenerating(false);
    }
  };

  if (!isAdmin) {
    return (
      <div className="min-h-[80vh] flex items-center justify-center px-6">
        <div className="max-w-md w-full bg-panda-white/5 border border-panda-white/10 p-12 rounded-[2.5rem] text-center backdrop-blur-xl">
          <div className="w-20 h-20 bg-panda-gold/10 text-panda-gold rounded-full flex items-center justify-center mx-auto mb-8 border border-panda-gold/20">
            <Lock size={32} />
          </div>
          <h1 className="text-3xl font-display font-bold mb-2 uppercase tracking-tighter">Accès Réservé</h1>
          <p className="text-panda-white/40 text-sm mb-10 font-light">Espace administrateur Panda_Graphic</p>
          <form onSubmit={handleAuth} className="space-y-6">
            <input 
              type="password"
              placeholder="••••••••"
              value={code}
              onChange={(e) => { setCode(e.target.value); setError(false); }}
              className={`w-full bg-panda-black border px-6 py-4 rounded-xl outline-none text-center text-2xl tracking-[0.5em] transition-all ${
                error ? 'border-red-500 animate-shake' : 'border-panda-white/10 focus:border-panda-gold'
              }`}
            />
            {error && <p className="text-red-500 text-xs font-bold uppercase tracking-widest">Code incorrect</p>}
            <button className="w-full py-5 bg-panda-gold text-panda-black font-bold uppercase tracking-[0.3em] rounded-xl hover:bg-panda-gold/90 transition-all flex items-center justify-center space-x-3">
              <span>DÉBLOQUER</span>
              <ArrowRight size={18} />
            </button>
          </form>
        </div>
      </div>
    );
  }

  return (
    <div className="max-w-7xl mx-auto px-6 py-20 animate-in fade-in duration-700 relative z-10">
      <header className="flex flex-col md:flex-row md:items-center justify-between gap-8 mb-16">
        <div className="flex items-center space-x-6">
          <div className="p-4 bg-panda-green/20 text-panda-green rounded-2xl border border-panda-green/30">
            <Unlock size={24} />
          </div>
          <div>
            <h1 className="text-4xl font-display font-bold uppercase tracking-tighter text-panda-white">Dashboard <span className="text-panda-gold">Victor</span></h1>
            <p className="text-panda-white/40 font-light">Gestion du portfolio et du blog</p>
          </div>
        </div>
        <div className="flex bg-panda-white/5 p-1 rounded-2xl border border-panda-white/10">
          {[
            { id: 'projects', icon: <Layout size={18} />, label: 'Portfolio' },
            { id: 'blog', icon: <BookOpen size={18} />, label: 'Blog' },
            { id: 'appointments', icon: <Calendar size={18} />, label: 'Rendez-vous' }
          ].map(t => (
            <button
              key={t.id}
              onClick={() => setTab(t.id as any)}
              className={`flex items-center space-x-2 px-6 py-3 rounded-xl transition-all uppercase tracking-[0.2em] text-[10px] font-black ${
                tab === t.id ? 'bg-panda-gold text-panda-black shadow-lg shadow-panda-gold/20' : 'hover:bg-panda-white/5 text-panda-white/40 hover:text-panda-white'
