import { defineConfig } from 'vite';
import react from '@vitejs/plugin-react';

export default defineConfig({
  plugins: [react()],
  define: {
    'process.env.API_KEY': JSON.stringify(process.env.API_KEY)
  },
  build: {
    outDir: 'dist',
    emptyOutDir: true
  }
});

import { GoogleGenAI, Type } from "@google/genai";

// On initialise l'IA uniquement si la clé existe pour éviter de bloquer l'application
const apiKey = process.env.API_KEY;

export const translateContent = async (text: string, targetLang: string) => {
  if (!apiKey || apiKey === "undefined" || apiKey === "none") {
    console.warn("Gemini API Key manquante. Traduction désactivée.");
    return text;
  }

  try {
    const ai = new GoogleGenAI({ apiKey });
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Translate the following text into ${targetLang}. Only return the translation: "${text}"`,
    });
    return response.text?.trim() || text;
  } catch (error) {
    console.error("Translation error:", error);
    return text;
  }
};

export const generateBlogPost = async (topic: string, lang: string) => {
  if (!apiKey || apiKey === "undefined" || apiKey === "none") {
    console.warn("Gemini API Key manquante. Génération désactivée.");
    return null;
  }

  try {
    const ai = new GoogleGenAI({ apiKey });
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Write a creative and professional blog post in ${lang} for a graphic design portfolio called Panda_Graphic about: ${topic}. Structure it with a title and body text.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            title: { type: Type.STRING },
            content: { type: Type.STRING }
          },
          required: ["title", "content"]
        }
      }
    });
    return JSON.parse(response.text || '{}');
  } catch (error) {
    console.error("Generation error:", error);
    return null;
  }
};

